  ('dietitian-moex-10619', 'dietitian', 'dietitian-moex-094-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列有關胺基酸的敘述，何者為真？ 黃豆蛋白質之第一限制胺基酸為Threonine 米飯蛋白質之第二限制胺基酸為Lysine Arginine為一種Basic amino acid Serine為一種Branched-chain amino acid', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "de86e5e3c8c3", "answer_pdf_sha1": "794bf55cd1a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
